const item = $input.first();
const body = item.json?.body || item.json || {};
const binary = item.binary || {};
const audioKey = body.audio_binary_key || Object.keys(binary)[0] || '';
const audio = audioKey ? binary[audioKey] : null;

const rawDemo = body.demo_data_confirmed;
const demoString = Array.isArray(rawDemo)
  ? rawDemo.join(' ').toLowerCase()
  : String(rawDemo ?? '').toLowerCase().trim();

const demo =
  rawDemo === true ||
  rawDemo === 1 ||
  ['true', 'on', 'yes', 'checked', '1', 'demo_data_confirmed'].includes(demoString) ||
  (Array.isArray(rawDemo) && rawDemo.length > 0);

const required = {
  meeting_title: String(body.meeting_title || '').trim(),
  department: String(body.department || '').trim(),
  meeting_type: String(body.meeting_type || '').trim(),
  reviewer_name: String(body.reviewer_name || '').trim(),
};

const missingFields = Object.entries(required)
  .filter(([, value]) => !value)
  .map(([key]) => key);

const mimeType = String(audio?.mimeType || audio?.mime || '').toLowerCase();
const supportedMime =
  ['audio/mpeg', 'audio/mp3', 'audio/wav', 'audio/x-wav', 'audio/mp4', 'audio/m4a', 'audio/x-m4a'].includes(mimeType) ||
  mimeType.startsWith('audio/');

const errors = [];
if (!demo) errors.push('Demo audio not confirmed.');
if (missingFields.length) errors.push(`Missing required fields: ${missingFields.join(', ')}.`);
if (!audio) errors.push('Audio file is missing.');
if (audio && !supportedMime) errors.push(`Unsupported audio MIME type: ${mimeType || 'unknown'}.`);

let audioBase64 = '';
if (audio && supportedMime) {
  try {
    const buffer = await this.helpers.getBinaryDataBuffer(0, audioKey);
    audioBase64 = buffer.toString('base64');
  } catch (error) {
    errors.push(`Could not read audio binary data: ${error.message}.`);
  }
}

const audio_ok = errors.length === 0;

return [{
  json: {
    ...body,
    ...required,
    audience: String(body.audience || '').trim(),
    language_hint: String(body.language_hint || '').trim(),
    notify_channel: String(body.notify_channel || 'none').trim() || 'none',
    demo_data_confirmed: demo,
    audio_binary_key: audioKey,
    audio_file_name: audio?.fileName || '',
    audio_mime_type: audio?.mimeType || audio?.mime || 'audio/mpeg',
    audio_base64: audioBase64,
    source_mode: 'gemini_audio_post_mvp',
    audio_ok,
    status: audio_ok ? 'audio_received' : 'audio_rejected_input',
    error_message: errors.join(' '),
  },
}];

const prompt = `Generate a transcript of this fake/demo meeting audio. Return JSON only.\n\nReturn this JSON shape:\n{\n  "transcript_language": "string",\n  "transcript_text": "string",\n  "speaker_notes": [{ "speaker": "string|null", "text": "string" }],\n  "quality_notes": ["string"]\n}\n\nDo not summarize. Do not add business follow-up. If audio is unclear, mark the unclear section in transcript_text and add a quality note.`;
const gemini_body = {
  contents: [
    {
      parts: [
        { text: prompt },
        {
          inlineData: {
            mimeType: $json.audio_mime_type || 'audio/mpeg',
            data: $json.audio_base64,
          },
        },
      ],
    },
  ],
  generationConfig: {
    responseMimeType: 'application/json',
    responseJsonSchema: {
      type: 'object',
      additionalProperties: false,
      required: ['transcript_language', 'transcript_text', 'speaker_notes', 'quality_notes'],
      properties: {
        transcript_language: { type: 'string' },
        transcript_text: { type: 'string' },
        speaker_notes: {
          type: 'array',
          items: {
            type: 'object',
            additionalProperties: false,
            required: ['speaker', 'text'],
            properties: {
              speaker: { type: ['string', 'null'] },
              text: { type: 'string' },
            },
          },
        },
        quality_notes: { type: 'array', items: { type: 'string' } },
      },
    },
  },
};
const { audio_base64, ...safeMeta } = $json;
return [{ json: { ...safeMeta, gemini_body } }];

const item = $input.first().json;

const raw =
  item.message ||
  item.error?.message ||
  item.errorMessage ||
  item.description ||
  '';

let parsedMessage = '';
let statusCode = item.statusCode || item.status || item.response?.status || '';

const rawString = String(raw);

const jsonMatch = rawString.match(/\{[\s\S]*\}/);
if (jsonMatch) {
  try {
    const parsed = JSON.parse(jsonMatch[0]);
    parsedMessage = parsed?.error?.message || '';
    statusCode = parsed?.error?.code || statusCode;
  } catch (error) {
    parsedMessage = '';
  }
}

const normalizedRaw = `${statusCode} ${rawString} ${parsedMessage}`.toLowerCase();

let status = 'gemini_transcription_failed';
let error_message = 'Gemini transcription failed. Use manual transcript input as fallback.';

if (
  normalizedRaw.includes('503') ||
  normalizedRaw.includes('unavailable') ||
  normalizedRaw.includes('high demand')
) {
  status = 'gemini_transcription_unavailable';
  error_message = 'Gemini transcription is temporarily unavailable because the model is under high demand. Try again later or paste the transcript manually.';
} else if (
  normalizedRaw.includes('404') ||
  normalizedRaw.includes('not found') ||
  normalizedRaw.includes('model')
) {
  status = 'gemini_model_not_available';
  error_message = 'The configured Gemini model is not available for this API key. Check the model name and project quota.';
} else if (
  normalizedRaw.includes('429') ||
  normalizedRaw.includes('rate') ||
  normalizedRaw.includes('quota') ||
  normalizedRaw.includes('spacing your requests')
) {
  status = 'gemini_rate_limited';
  error_message = 'Gemini rate limit was reached. Wait briefly and try again, or paste the transcript manually.';
} else if (
  normalizedRaw.includes('401') ||
  normalizedRaw.includes('403') ||
  normalizedRaw.includes('api key') ||
  normalizedRaw.includes('permission')
) {
  status = 'gemini_auth_failed';
  error_message = 'Gemini authentication failed. Check the API key or Gemini project permissions.';
}

return [{
  json: {
    ok: false,
    status,
    error_message,
    raw_error_message: rawString.slice(0, 500),
  },
}];

let meta = {};
try { meta = $('Build Gemini Transcript Request').first().json; } catch (error) {}
const response = $input.first().json;
const text = response?.candidates?.[0]?.content?.parts?.[0]?.text || response?.text || '';
let parsed;
try {
  parsed = typeof text === 'string' ? JSON.parse(text) : text;
} catch (error) {
  return [{ json: { ok: false, status: 'gemini_transcript_parse_failed', error_message: `Gemini returned non-JSON transcript: ${String(error.message).slice(0, 240)}` } }];
}
const transcript = String(parsed?.transcript_text || '').trim();
if (transcript.length < 50) {
  return [{ json: { ok: false, status: 'gemini_transcript_empty', error_message: 'Gemini transcript was empty or too short.' } }];
}
return [{ json: {
  ok: true,
  meeting_title: meta.meeting_title,
  department: meta.department,
  meeting_type: meta.meeting_type,
  audience: meta.audience,
  language_hint: meta.language_hint || parsed.transcript_language || '',
  reviewer_name: meta.reviewer_name,
  notify_channel: meta.notify_channel || 'none',
  demo_data_confirmed: true,
  source_mode: 'gemini_audio_post_mvp',
  manual_transcript: transcript,
  transcript_language: parsed.transcript_language || '',
  speaker_notes_json: JSON.stringify(parsed.speaker_notes || []),
  quality_notes_json: JSON.stringify(parsed.quality_notes || []),
} }];

const item = $input.first().json;
const rawMessage = item.message || item.error?.message || item.errorMessage || item.description || 'Create Draft API call failed after transcription.';
return [{ json: { ok: false, status: 'audio_create_draft_failed', error_message: String(rawMessage).slice(0, 500) } }];
